const itemBasePremium = (item: Item): number => {
  if (item.type === "sword") {
    return 100 + 10; // base + first insurance surcharge
  }
  return 0;
};

const quotePremium = (items: Item[]): number => {
  const baseTotal = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
  return roundUp(baseTotal) + PROCESSING_FEE;
};
